import{_ as e,o as r,c as t,ah as i}from"./chunks/framework.D-EW4Mou.js";const u=JSON.parse('{"title":"监控指标设计","description":"","frontmatter":{"title":"监控指标设计","order":2},"headers":[],"relativePath":"server/distribute/qos/observability/monitoring.md","filePath":"server/distribute/qos/observability/monitoring.md"}'),h={name:"server/distribute/qos/observability/monitoring.md"};function o(s,a,l,n,d,c){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="监控指标设计" tabindex="-1">监控指标设计 <a class="header-anchor" href="#监控指标设计" aria-label="Permalink to “监控指标设计”">​</a></h1><p>好的监控指标能够快速发现异常、定位问题、优化性能。本节介绍如何设计有效的监控指标。</p><h2 id="red-方法" tabindex="-1">RED 方法 <a class="header-anchor" href="#red-方法" aria-label="Permalink to “RED 方法”">​</a></h2><p>RED 方法是 Weaveworks 提出的监控指标设计方法，专注于请求相关的指标。</p><h3 id="rate-速率" tabindex="-1">Rate（速率） <a class="header-anchor" href="#rate-速率" aria-label="Permalink to “Rate（速率）”">​</a></h3><p>每秒请求数，反映系统的负载。可以按服务、端点、状态码分组。Rate = 请求数 / 时间窗口。例如 http_requests_total / 60s 表示最近 60 秒的 QPS。</p><h3 id="errors-错误" tabindex="-1">Errors（错误） <a class="header-anchor" href="#errors-错误" aria-label="Permalink to “Errors（错误）”">​</a></h3><p>错误请求数，反映系统的健康度。错误率 = 错误请求数 / 总请求数。错误可以按状态码分类（4xx 客户端错误、5xx 服务器错误）。4xx 可能是客户端问题，5xx 是服务器问题。</p><h3 id="duration-持续时间" tabindex="-1">Duration（持续时间） <a class="header-anchor" href="#duration-持续时间" aria-label="Permalink to “Duration（持续时间）”">​</a></h3><p>请求的处理时间，反映系统的性能。Duration 可以用 P50（中位数）、P95（95 分位数）、P99（99 分位数）表示。P99 延迟是重要的性能指标，反映了最差的 1% 用户体验。</p><h2 id="use-方法" tabindex="-1">USE 方法 <a class="header-anchor" href="#use-方法" aria-label="Permalink to “USE 方法”">​</a></h2><p>USE 方法是 Brendan Gregg 提出的监控资源的方法，专注于资源利用率。</p><h3 id="utilization-利用率" tabindex="-1">Utilization（利用率） <a class="header-anchor" href="#utilization-利用率" aria-label="Permalink to “Utilization（利用率）”">​</a></h3><p>资源的使用百分比，如 CPU 使用率、内存使用率、磁盘使用率。利用率过高（&gt;80%）表示资源紧张，需要扩容或优化。</p><h3 id="saturation-饱和度" tabindex="-1">Saturation（饱和度） <a class="header-anchor" href="#saturation-饱和度" aria-label="Permalink to “Saturation（饱和度）”">​</a></h3><p>资源的负载程度，如 CPU 运行队列长度、磁盘 I/O 等待时间、网络连接数。饱和度高表示资源过载，请求排队等待。</p><h3 id="errors-错误-1" tabindex="-1">Errors（错误） <a class="header-anchor" href="#errors-错误-1" aria-label="Permalink to “Errors（错误）”">​</a></h3><p>资源的错误数，如磁盘 I/O 错误、网络错误、内存页错误。错误增加表示硬件故障或配置错误。</p><h2 id="指标类型" tabindex="-1">指标类型 <a class="header-anchor" href="#指标类型" aria-label="Permalink to “指标类型”">​</a></h2><h3 id="counter-计数器" tabindex="-1">Counter（计数器） <a class="header-anchor" href="#counter-计数器" aria-label="Permalink to “Counter（计数器）”">​</a></h3><p>Counter 是只增不减的数值，适合累积事件。例如：http_requests_total（总请求数）、errors_total（总错误数）。Counter 的速率（rate）表示每秒增量，如 rate(http_requests_total[5m]) 表示最近 5 分钟的平均 QPS。</p><h3 id="gauge-仪表盘" tabindex="-1">Gauge（仪表盘） <a class="header-anchor" href="#gauge-仪表盘" aria-label="Permalink to “Gauge（仪表盘）”">​</a></h3><p>Gauge 是可增可减的数值，适合瞬时状态。例如：memory_usage_bytes（内存使用量）、thread_count（线程数）、temperature_celsius（温度）。Gauge 的当前值反映系统状态，不需要计算速率。</p><h3 id="histogram-直方图" tabindex="-1">Histogram（直方图） <a class="header-anchor" href="#histogram-直方图" aria-label="Permalink to “Histogram（直方图）”">​</a></h3><p>Histogram 是样本的分布统计，适合延迟、请求大小等。Histogram 包含：_count（样本数）、_sum（样本总和）、_bucket（桶计数）。Histogram 可以计算分位数，如 histogram_quantile(0.95, rate(http_duration_seconds_bucket[5m])) 表示 P95 延迟。</p><h3 id="summary-摘要" tabindex="-1">Summary（摘要） <a class="header-anchor" href="#summary-摘要" aria-label="Permalink to “Summary（摘要）”">​</a></h3><p>Summary 是客户端计算的分布统计，适合延迟。Summary 包含：_count（样本数）、_sum（样本总和）、quantile（分位数）。Summary 的分位数是客户端计算的，无法聚合多个实例的分位数。Histogram 的分位数是服务器计算的，可以聚合。</p><h2 id="指标命名" tabindex="-1">指标命名 <a class="header-anchor" href="#指标命名" aria-label="Permalink to “指标命名”">​</a></h2><h3 id="指标名称规范" tabindex="-1">指标名称规范 <a class="header-anchor" href="#指标名称规范" aria-label="Permalink to “指标名称规范”">​</a></h3><p>指标名用小写字母和下划线，单位用后缀表示。例如：http_requests_total（总数）、http_duration_seconds（秒）、memory_usage_bytes（字节）。避免使用缩写，用 latency 而不是 lat。</p><h3 id="标签-label" tabindex="-1">标签（Label） <a class="header-anchor" href="#标签-label" aria-label="Permalink to “标签（Label）”">​</a></h3><p>标签是指标的维度，用于分组和过滤。例如：http_requests_total{method=&quot;GET&quot;, status=&quot;200&quot;} 表示 GET 请求且状态码 200 的总数。标签是字符串，枚举值（如 status）比数字（如 status_code）更高效。</p><h3 id="基数-cardinality" tabindex="-1">基数（Cardinality） <a class="header-anchor" href="#基数-cardinality" aria-label="Permalink to “基数（Cardinality）”">​</a></h3><p>基数是标签的唯一值数量，高基数会导致指标爆炸。例如 user_id 有百万用户，基数是百万，会导致百万条时序数据。避免高基数标签，如 user_id、request_id。低基数标签，如 service、endpoint、status。</p><h2 id="指标聚合" tabindex="-1">指标聚合 <a class="header-anchor" href="#指标聚合" aria-label="Permalink to “指标聚合”">​</a></h2><h3 id="聚合操作" tabindex="-1">聚合操作 <a class="header-anchor" href="#聚合操作" aria-label="Permalink to “聚合操作”">​</a></h3><p>sum（求和）：sum(http_requests_total) 表示所有实例的总请求数。avg（平均）：avg(memory_usage_bytes) 表示所有实例的平均内存使用。max/min（最大值/最小值）：max(cpu_usage) 表示所有实例的最大 CPU 使用。</p><h3 id="分组聚合" tabindex="-1">分组聚合 <a class="header-anchor" href="#分组聚合" aria-label="Permalink to “分组聚合”">​</a></h3><p>by（按标签分组）：sum(http_requests_total) by (service) 表示每个服务的总请求数。without（排除标签）：sum(http_requests_total) without (instance) 表示所有实例的总请求数（忽略 instance 标签）。</p><h2 id="金金指标" tabindex="-1">金金指标 <a class="header-anchor" href="#金金指标" aria-label="Permalink to “金金指标”">​</a></h2><p>Google SRE 书中提出的四个黄金指标：延迟（Duration）、流量（Traffic）、错误（Errors）、饱和度（Saturation）。</p><h3 id="延迟" tabindex="-1">延迟 <a class="header-anchor" href="#延迟" aria-label="Permalink to “延迟”">​</a></h3><p>延迟是请求的处理时间，用 P50、P95、P99 表示。P99 延迟是最重要的性能指标，反映了最差的 1% 用户体验。监控成功请求和失败请求的延迟，失败请求可能很快（快速失败）。</p><h3 id="流量" tabindex="-1">流量 <a class="header-anchor" href="#流量" aria-label="Permalink to “流量”">​</a></h3><p>流量是每秒请求数，反映系统负载。可以按服务、端点、客户分组。流量突增可能是攻击、故障或正常增长。</p><h3 id="错误" tabindex="-1">错误 <a class="header-anchor" href="#错误" aria-label="Permalink to “错误”">​</a></h3><p>错误是失败的请求数，反映系统健康度。错误率 = 错误请求数 / 总请求数。区分客户端错误（4xx）和服务器错误（5xx），4xx 可能是客户端问题，5xx 是服务器问题。</p><h3 id="饱和度" tabindex="-1">饱和度 <a class="header-anchor" href="#饱和度" aria-label="Permalink to “饱和度”">​</a></h3><p>饱和度是资源的负载程度，如 CPU、内存、磁盘、网络。饱和度高表示资源过载，需要扩容或优化。CPU 运行队列长度、磁盘 I/O 等待时间、网络连接数都是饱和度指标。</p><h2 id="告警规则" tabindex="-1">告警规则 <a class="header-anchor" href="#告警规则" aria-label="Permalink to “告警规则”">​</a></h2><h3 id="告警阈值" tabindex="-1">告警阈值 <a class="header-anchor" href="#告警阈值" aria-label="Permalink to “告警阈值”">​</a></h3><p>阈值应该基于历史数据，而不是随意设置。例如 P95 延迟的告警阈值设为历史 P95 的 2 倍。阈值应该有容忍度，避免告警风暴。</p><h3 id="告警持续时间" tabindex="-1">告警持续时间 <a class="header-anchor" href="#告警持续时间" aria-label="Permalink to “告警持续时间”">​</a></h3><p>告警持续时间（for）是条件持续多久才触发告警。避免瞬时波动触发告警。例如 rate(errors_total[5m]) &gt; 0.01 for 10m 表示错误率超过 1% 持续 10 分钟才告警。</p><h3 id="告警优先级" tabindex="-1">告警优先级 <a class="header-anchor" href="#告警优先级" aria-label="Permalink to “告警优先级”">​</a></h3><p>告警按优先级分类：P0（严重，如服务宕机）、P1（高，如错误率突增）、P2（中，如性能下降）、P3（低，如资源紧张）。不同优先级的告警有不同的响应时间、通知渠道、升级策略。</p>',56)])])}const b=e(h,[["render",o]]);export{u as __pageData,b as default};
